code.C:
int findMaxProfit(int prices[], int n) {
    int minPrice = INT_MAX;
    int maxProfit = 0;

    for (int i = 0; i < n; i++) {
        if (prices[i] < minPrice) {
            minPrice = prices[i]; // update minimum seen so far
        } else if (prices[i] - minPrice > maxProfit) {
            maxProfit = prices[i] - minPrice; // update max profit
        }
    }
    return maxProfit;
}

